import{_ as a,o as t,c as n,a2 as s}from"./chunks/framework.BWuWLRhz.js";const m=JSON.parse('{"title":"AnimeTV for Android TV & Google TV","description":"","frontmatter":{},"headers":[],"relativePath":"README.md","filePath":"README.md"}'),i={name:"README.md"};function r(o,e,l,p,c,d){return t(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="animetv-for-android-tv-google-tv" tabindex="-1">AnimeTV for Android TV &amp; Google TV <a class="header-anchor" href="#animetv-for-android-tv-google-tv" aria-label="Permalink to &quot;AnimeTV for Android TV &amp; Google TV&quot;">​</a></h1><p>AnimeTV is Android TV application for watching your favorite anime series and movies on your Android TV, It also runs on non-TV Android devices (Phones and Tablets) with some UI limitations.</p><blockquote><p>Source data is from <em>one anime streaming website</em> and I don&#39;t have any affiliation with it, and it may break on site updates. Take a look at source code for more info</p></blockquote><p><a href="https://amarullz.com/" target="_blank" rel="noreferrer"><img src="https://raw.githubusercontent.com/AnimeTV-Fork/docs/main/tools/logo-design/animetv-logo/animetv-logo-brand.png" alt="AnimeTV"></a></p><h2 id="download-url-and-code" tabindex="-1">Download URL and Code <a class="header-anchor" href="#download-url-and-code" aria-label="Permalink to &quot;Download URL and Code&quot;">​</a></h2><ul><li><strong>STABLE APK</strong><ul><li>URL: <a href="https://animetv.amarullz.com/apk" target="_blank" rel="noreferrer">https://animetv.amarullz.com/apk</a></li><li>AFTV Downloader code: <strong><code>601972</code></strong></li></ul></li><li><strong>NIGHTLY APK</strong><ul><li>URL: <a href="https://animetv.amarullz.com/nightly" target="_blank" rel="noreferrer">https://animetv.amarullz.com/nightly</a></li><li>AFTV Downloader code: <strong><code>196130</code></strong></li></ul></li></ul><p><a href="https://www.youtube.com/watch?v=Cx3eJcTect4" target="_blank" rel="noreferrer"><img src="https://img.youtube.com/vi/Cx3eJcTect4/hqdefault.jpg" alt="TIPS"></a></p><h2 id="donation-more-information" tabindex="-1">Donation &amp; More Information <a class="header-anchor" href="#donation-more-information" aria-label="Permalink to &quot;Donation &amp; More Information&quot;">​</a></h2><table tabindex="0"><thead><tr><th>License</th><th>Stable Release</th><th>Nightly Release</th><th>Support</th></tr></thead><tbody><tr><td><a href="/LICENSE.html"><img src="https://img.shields.io/github/license/amarullz/AnimeTV" alt="GitHub License"></a></td><td><a href="https://github.com/amarullz/AnimeTV/releases" target="_blank" rel="noreferrer"><img src="https://img.shields.io/github/v/release/amarullz/AnimeTV?logo=github&amp;label=Release" alt="GitHub Release"></a></td><td><a href="https://amarullz.com/animetv-nightly/" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/dynamic/json?url=https%3A%2F%2Fanimetv.amarullz.com%2Flast-nightly&amp;query=%24%5B0%5D.name&amp;style=flat&amp;logo=amp&amp;logoColor=fff&amp;label=Nightly&amp;color=800" alt="Nightly"></a></td><td><a href="https://discord.gg/VGtGtRedGR" target="_blank" rel="noreferrer"><img src="https://img.shields.io/discord/1199444562670792714?style=flat&amp;labelColor=7289da&amp;color=2c2f33&amp;label=Discord&amp;logo=discord&amp;logoColor=ffffff" alt="Discord"></a></td></tr></tbody></table><ul><li><strong>Donate Project :</strong> <a href="https://paypal.me/amarullz" target="_blank" rel="noreferrer">Paypal Link - https://paypal.me/amarullz</a></li><li><strong>Developer Website :</strong> <a href="https://amarullz.com/" target="_blank" rel="noreferrer">https://amarullz.com/</a></li><li><strong>Nightly Release :</strong> <a href="https://amarullz.com/animetv-nightly/" target="_blank" rel="noreferrer">https://amarullz.com/animetv-nightly/</a></li><li><strong>Development Discussion :</strong> <a href="https://amarullz.com/animetv-discord/" target="_blank" rel="noreferrer">https://amarullz.com/animetv-discord/</a></li><li><strong>More Detail Information :</strong> <a href="https://amarullz.com/animetv/" target="_blank" rel="noreferrer">https://amarullz.com/animetv/</a></li><li><strong>Join Discussion on Discord :</strong> <a href="https://discord.com/invite/y5tVXynE" target="_blank" rel="noreferrer">https://discord.com/invite/y5tVXynE</a></li></ul><h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h2><ul><li><strong>NEW</strong> - UI Interface with Trailer Video</li><li><strong>NEW</strong> - 6 Different sources</li><li><strong>NEW</strong> - List reorder / management</li><li><strong>NEW</strong> - Auto Update App and in app nightly build installation</li><li><strong>NEW</strong> - Airing Schedule</li><li><strong>NEW</strong> - MAL &amp; AniList Integration</li><li><strong>NEW</strong> - DNS over HTTPS and Multiple HTTP Client selection</li><li><strong>NEW</strong> - Mirror Stream Server</li><li><strong>NEW</strong> - Soft-subtitle &amp; Auto Translate to <strong>134 Languages</strong> (Only for supported contents)</li><li><strong>NEW</strong> - Settings panel</li><li><strong>NEW</strong> - Change Theme Color &amp; Animation performance</li><li><strong>NEW</strong> - Soft-subtitle Text Style Configuration</li><li><strong>NEW</strong> - Playback Speed (0.5x - 3.00x)</li><li><strong>NEW</strong> - Include Non-Japan Anime Settings</li><li>Search and Advance Search with Genre &amp; Anime Type filters</li><li>Auto Next episode</li><li>Auto Skip Intro &amp; Outro</li><li>Auto Skip Filler Episode</li><li>Genre &amp; Type Tags</li><li>Video display style ( Centered, Fit, Scaled ) for non widescreen videos.</li><li>Easy to navigate with Android TV Remote</li><li>Home Anime List <ul><li>Hot</li><li>Recently Updated</li><li>Dub Update</li><li>Top Anime</li><li>Trending Episodes</li><li>Random Anime</li><li>Watchlist Anime – You can set anime as favorite to watch</li><li>Watch History – All anime has been watched before with last timestamp</li></ul></li><li>List of episodes and seasons for show</li><li>Recommendation anime for current show</li><li>Support for Android TV / Google TV home list and PlayNext</li><li>All Watchlist &amp; History is saved locally – I don’t have any server to save your watch &amp; history 🤣 So don’t worry.</li></ul><h2 id="architecture-clean-architecture-—-typescript" tabindex="-1">Architecture (Clean Architecture — TypeScript) <a class="header-anchor" href="#architecture-clean-architecture-—-typescript" aria-label="Permalink to &quot;Architecture (Clean Architecture — TypeScript)&quot;">​</a></h2><p>The new <code>src/</code> directory implements a <strong>Clean Architecture</strong> refactor of the core logic. It sits alongside the legacy code in <code>electron/src/</code> and <code>app/src/main/assets/view/</code> and will progressively replace it.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>src/</span></span>
<span class="line"><span>├── core/              ← Shared primitives (no dependencies)</span></span>
<span class="line"><span>│   ├── types/         Result&lt;T,E&gt;, Option&lt;T&gt; — typed error handling</span></span>
<span class="line"><span>│   ├── errors/        AppError hierarchy (Stream, Auth, Data, Config, Validation)</span></span>
<span class="line"><span>│   └── utils/         pipe(), compose(), pipeAsync() — FP composition</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── domain/            ← Business rules (depends only on core)</span></span>
<span class="line"><span>│   ├── entities/      Anime, Episode, StreamSource, AuthToken</span></span>
<span class="line"><span>│   ├── repositories/  Port interfaces (AnimeRepository, AuthRepository)</span></span>
<span class="line"><span>│   └── usecases/      GetStreamSources, GetEpisodes, SearchAnime, Authenticate</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── data/              ← Infrastructure adapters (depends on domain + core)</span></span>
<span class="line"><span>│   ├── network/       HttpClient interface + ElectronHttpClient implementation</span></span>
<span class="line"><span>│   ├── datasources/   MiruroPipe, ServerConfig, OneAnime typed interfaces + impls</span></span>
<span class="line"><span>│   └── repositories/  AnimeRepositoryImpl (DTO→Entity mapping, provider fallback)</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── presentation/      ← UI/Controller layer (depends on domain + data)</span></span>
<span class="line"><span>│   ├── state/         Immutable AppState, reducer, minimal store (Redux-like)</span></span>
<span class="line"><span>│   └── interceptor/   CDN Registry, declarative Request Router</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>└── di/                ← Dependency injection (wires everything)</span></span>
<span class="line"><span>    └── container.ts   Pure-function DI — no decorators or reflection</span></span></code></pre></div><h3 id="key-design-decisions" tabindex="-1">Key Design Decisions <a class="header-anchor" href="#key-design-decisions" aria-label="Permalink to &quot;Key Design Decisions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Decision</th><th>Rationale</th></tr></thead><tbody><tr><td><code>Result&lt;T, E&gt;</code> instead of exceptions</td><td>Forces callers to handle errors; no uncaught crashes</td></tr><tr><td>Immutable entities (<code>readonly</code> everywhere)</td><td>Prevents accidental mutation bugs</td></tr><tr><td>Repository port interfaces</td><td>Domain doesn&#39;t know about HTTP, Electron, or any CDN</td></tr><tr><td>CDN Registry (single source of truth)</td><td>Previously duplicated 3× across interceptor.js</td></tr><tr><td>Declarative route table</td><td>Each route is testable in isolation; no 600-line if/else</td></tr><tr><td>Pure-function DI container</td><td>No decorators/reflection — just functions calling functions</td></tr></tbody></table><h3 id="running-the-new-layer" tabindex="-1">Running the new layer <a class="header-anchor" href="#running-the-new-layer" aria-label="Permalink to &quot;Running the new layer&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Type-check</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tsc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --noEmit</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Run tests (71 tests)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vitest</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Lint + format</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> eslint</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> prettier</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --check</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/</span></span></code></pre></div><hr><h2 id="open-source" tabindex="-1">Open Source <a class="header-anchor" href="#open-source" aria-label="Permalink to &quot;Open Source&quot;">​</a></h2><p>Source code is available at github ( <a href="https://github.com/amarullz/AnimeTV" target="_blank" rel="noreferrer">https://github.com/amarullz/AnimeTV</a> ). Release of source code may make <em>source website</em> prevent this apps to run, but hope it work fine for long, and you will help me update it when it break 😂.</p><p>And Please Contribute your bugfixes, reports &amp; suggestions for next better update. If you find it useful, donation is welcome.</p><h2 id="webview-based" tabindex="-1">WebView Based? <a class="header-anchor" href="#webview-based" aria-label="Permalink to &quot;WebView Based?&quot;">​</a></h2><p>Yes, it was webview based application. UI and Data Fetch Method is using webview, because I don&#39;t have access to <em>source website</em> database, I just load the web in headless webview and fetch site data info with javascript injection, because it&#39;s not possible to use only http client to get data.</p><p>Almost all data need javascript to make it available (It&#39;s not pure HTML that can easily parsed from text). The site also use <strong>QUIC</strong> rather than HTTP1X, so I need to include <strong>CronetEngine</strong> to make it works.</p><p>But the good news is <strong>AnimeTV</strong> will block any analytics and ads domain (dns) when requesting &amp; fetching data. All data like watchlist &amp; watch history also stored local in <strong>localStorage</strong>.</p><h2 id="screenshot" tabindex="-1">Screenshot <a class="header-anchor" href="#screenshot" aria-label="Permalink to &quot;Screenshot&quot;">​</a></h2><p>More screenshot is available in my website: <a href="https://amarullz.com/animetv/" target="_blank" rel="noreferrer">https://amarullz.com/animetv/</a> Here only a couple screenshot:</p><p><img src="https://github.com/amarullz/AnimeTV/assets/1386831/d05c7e5d-8abc-4fed-9183-0c58aa815c44" alt="Homescreen"></p><p><img src="https://github.com/amarullz/AnimeTV/assets/1386831/68686765-a7eb-4fe8-bc69-f69996053a5d" alt="Settings"></p><p><img src="https://github.com/amarullz/AnimeTV/assets/1386831/c8854596-1984-4c54-993d-d358d9943e7d" alt="Anime Popup"></p><p><img src="https://github.com/amarullz/AnimeTV/assets/1386831/9d8a9e51-c3a0-43c0-a487-c9fb36949c43" alt="MyList"></p><p><img src="https://github.com/amarullz/AnimeTV/assets/1386831/b1c86f23-5ca3-4008-95f6-c3107e062f07" alt="Customize &amp; Ordering"></p><p><img src="https://github.com/amarullz/AnimeTV/assets/1386831/59e722d8-f695-4245-8783-1d1675906c98" alt="TV friendly search"></p><p><img src="https://github.com/amarullz/AnimeTV/assets/1386831/ff1c0363-746d-4216-831b-cf60f4dce243" alt="Playback"></p><h2 id="disclaimer" tabindex="-1">DISCLAIMER <a class="header-anchor" href="#disclaimer" aria-label="Permalink to &quot;DISCLAIMER&quot;">​</a></h2><ul><li><p>AnimeTV only scrapes links from various websites and makes it easier for users to find anime.</p></li><li><p>AnimeTV or any of its developer doesn&#39;t host any of the contents found inside the app. All images and anime information found in the app are taken from various public APIs.</p></li><li><p>All anime found in AnimeTV are taken from various 3rd party anime hosting websites.</p></li><li><p>AnimeTV or it&#39;s owners aren&#39;t liable for any misuse of any of the contents found inside or outside of the app and cannot be held accountable for the distribution of any of the contents found inside the app.</p></li><li><p>By using AnimeTV, you comply to the fact that the developer of the app is not responsible for any of the contents found in the app; nonetheless they may or may not be from their legitimate sources.</p></li><li><p>If the internet infringement issues are involved, please contact the source website. The developer does not assume any legal responsibility.</p></li></ul><h2 id="license" tabindex="-1">License <a class="header-anchor" href="#license" aria-label="Permalink to &quot;License&quot;">​</a></h2><p><strong>Copyright 2023 Ahmad Amarullah (<a href="https://amarullz.com" target="_blank" rel="noreferrer">https://amarullz.com</a>)</strong></p><p>Licensed under the Apache License, Version 2.0 (the &quot;License&quot;); you may not use this file except in compliance with the License. You may obtain a copy of the License at</p><p><a href="http://www.apache.org/licenses/LICENSE-2.0" target="_blank" rel="noreferrer">http://www.apache.org/licenses/LICENSE-2.0</a></p><p>Unless required by applicable law or agreed to in writing, software distributed under the License is distributed on an &quot;AS IS&quot; BASIS, WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied. See the License for the specific language governing permissions and limitations under the License.</p>`,43)])])}const u=a(i,[["render",r]]);export{m as __pageData,u as default};
